import sys
from collections import deque
def bfs(graph, start, end):
    queue = deque([start])
    visited = set()
    while queue:
        node = queue.popleft()
        if node == end:
            return True
        if node not in visited:
            visited.add(node)
            queue.extend(graph[node])
    return False

def read_input():
    R, B = map(int, input().split())
    rebels = []
    bases = []
    for _ in range(R):
        x, y = map(int, input().split())
        rebels.append((x, y))
    for _ in range(B):
        x, y = map(int, input().split())
        bases.append((x, y))
    return rebels, bases

def build_graph(rebels, bases):
    graph = {}
    for i, base in enumerate(bases):
        graph[base] = []
        for j, rebel in enumerate(rebels):
            if i != j:
                graph[base].append(rebel)
    return graph

def main():
    rebels, bases = read_input()
    graph = build_graph(rebels, bases)
    for base in bases:
        for rebel in rebels:
            if rebel not in graph[base]:
                return False
    return True

if __name__ == "__main__":
    if main():
        print("Yes")
    else:
        print("No")
